1	'use strict';
2	/**
3	 * GSD-T Token Capture Wrapper (M41 D1)
4	 *
5	 * Single reusable module every GSD-T spawn call site uses. Parses the
6	 * `usage` envelope from Claude's result frame, appends a row to
7	 * `.gsd-t/token-log.md`, and appends a schema-v1 JSONL record to
8	 * `.gsd-t/metrics/token-usage.jsonl`.
9	 *
10	 * Zero external deps. `.cjs` so it loads in both ESM-default projects
11	 * and CJS projects without transpilation.
12	 *
13	 * Contracts:
14	 *   - .gsd-t/contracts/metrics-schema-contract.md (schema v1)
15	 *   - .gsd-t/contracts/stream-json-sink-contract.md v1.1.0 (usage semantics)
16	 *
17	 * Missing `usage` → write `—` in Tokens column. Never `0`, never `N/A`.
18	 */
19	
20	const fs = require('fs');
21	const path = require('path');
22	
23	const SCHEMA_VERSION = 2;
24	
25	const NEW_HEADER = '| Datetime-start | Datetime-end | Command | Step | Model | Duration(s) | Tokens | Notes | Domain | Task | Ctx% |';
26	const NEW_SEP    = '|---|---|---|---|---|---|---|---|---|---|---|';
27	
28	function pad2(n) { return String(n).padStart(2, '0'); }
29	function fmtDateTime(d) {
30	  return `${d.getFullYear()}-${pad2(d.getMonth()+1)}-${pad2(d.getDate())} ${pad2(d.getHours())}:${pad2(d.getMinutes())}`;
31	}
32	
33	function _parseUsageFromResult(result) {
34	  if (!result || typeof result !== 'object') return undefined;
35	  if (result.usage && typeof result.usage === 'object') return result.usage;
36	  if (result.result && typeof result.result === 'object' && result.result.usage && typeof result.result.usage === 'object') {
37	    return result.result.usage;
38	  }
39	  return undefined;
40	}
41	
42	function _formatTokensCell(usage) {
43	  if (!usage || typeof usage !== 'object') return '—';
44	  const inp = Number(usage.input_tokens || 0);
45	  const out = Number(usage.output_tokens || 0);
46	  const cr  = Number(usage.cache_read_input_tokens || 0);
47	  const cc  = Number(usage.cache_creation_input_tokens || 0);
48	  const costNum = (typeof usage.total_cost_usd === 'number') ? usage.total_cost_usd : (typeof usage.cost_usd === 'number' ? usage.cost_usd : null);
49	  const cost = (costNum == null) ? '—' : `$${costNum.toFixed(2)}`;
50	  if (!inp && !out && !cr && !cc && cost === '—') return '—';
51	  return `in=${inp} out=${out} cr=${cr} cc=${cc} ${cost}`;
52	}
53	
54	function _ensureDir(p) {
55	  const dir = path.dirname(p);
56	  if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
57	}
58	
59	function _ensureTokenLogHeader(tokenLogPath) {
60	  if (!fs.existsSync(tokenLogPath)) {
61	    _ensureDir(tokenLogPath);
62	    fs.writeFileSync(tokenLogPath, `# GSD-T Token Log\n\n${NEW_HEADER}\n${NEW_SEP}\n`);
63	    return;
64	  }
65	  const text = fs.readFileSync(tokenLogPath, 'utf8');
66	  if (text.includes(NEW_HEADER)) return;
67	  // Old header detection: first header line that starts with `| Datetime-start`
68	  const lines = text.split('\n');
69	  const headerIdx = lines.findIndex(l => /^\|\s*Datetime-start\s*\|/.test(l));
70	  if (headerIdx < 0) {
71	    // No header at all — append new one
72	    fs.writeFileSync(tokenLogPath, text.trimEnd() + `\n\n${NEW_HEADER}\n${NEW_SEP}\n`);
73	    return;
74	  }
75	  // Replace old header + separator with new header + separator, preserve existing rows
76	  const sepIdx = headerIdx + 1;
77	  lines[headerIdx] = NEW_HEADER;
78	  if (lines[sepIdx] && /^\|[\s\-|]+\|$/.test(lines[sepIdx])) {
79	    lines[sepIdx] = NEW_SEP;
80	  } else {
81	    lines.splice(sepIdx, 0, NEW_SEP);
82	  }
83	  fs.writeFileSync(tokenLogPath, lines.join('\n'));
84	}
85	
86	function _appendTokenLogRow(tokenLogPath, row) {
87	  _ensureTokenLogHeader(tokenLogPath);
88	  const line = `| ${row.startedAt} | ${row.endedAt} | ${row.command} | ${row.step} | ${row.model} | ${row.durationSec}s | ${row.tokensCell} | ${row.notes} | ${row.domain} | ${row.task} | ${row.ctxPct} |\n`;
89	  fs.appendFileSync(tokenLogPath, line);
90	}
91	
92	function _appendJsonlRecord(jsonlPath, record) {
93	  _ensureDir(jsonlPath);
94	  fs.appendFileSync(jsonlPath, JSON.stringify(record) + '\n');
95	}
96	
97	function _buildJsonlRecord({ command, step, model, startedAt, endedAt, durationSec, usage, domain, task, notes, ctxPct, milestone, source, sessionId, turnId, sessionType, toolAttribution, compactionPressure }) {
98	  const u = usage || {};
99	  const cost = (typeof u.total_cost_usd === 'number') ? u.total_cost_usd : (typeof u.cost_usd === 'number' ? u.cost_usd : null);
100	  const rec = {
101	    schemaVersion: SCHEMA_VERSION,
102	    ts: new Date().toISOString(),
103	    source: source || 'live',
104	    command,
105	    step,
106	    model,
107	    startedAt,
108	    endedAt,
109	    durationMs: durationSec * 1000,
110	    inputTokens: Number(u.input_tokens || 0),
111	    outputTokens: Number(u.output_tokens || 0),
112	    cacheReadInputTokens: Number(u.cache_read_input_tokens || 0),
113	    cacheCreationInputTokens: Number(u.cache_creation_input_tokens || 0),
114	    costUSD: cost,
115	    domain: domain || null,
116	    task: task || null,
117	    milestone: milestone || null,
118	    ctxPct: ctxPct == null ? null : ctxPct,
119	    notes: notes || null,
120	    hasUsage: !!usage,
121	  };
122	  if (sessionId != null)  rec.session_id  = String(sessionId);
123	  if (turnId != null)     rec.turn_id     = String(turnId);
124	  if (sessionType != null) rec.sessionType = sessionType;
125	  if (Array.isArray(toolAttribution) && toolAttribution.length) rec.tool_attribution = toolAttribution;
126	  if (compactionPressure && typeof compactionPressure === 'object') rec.compaction_pressure = compactionPressure;
127	  return rec;
128	}
129	
130	function _inferMilestone(projectDir) {
131	  try {
132	    const progress = fs.readFileSync(path.join(projectDir, '.gsd-t', 'progress.md'), 'utf8');
133	    const m = /\*\*(M\d+)\b/.exec(progress) || /## Status:\s*(M\d+)/.exec(progress);
134	    return m ? m[1] : null;
135	  } catch (_) { return null; }
136	}
137	
138	function _resolveCtxPct(projectDir) {
139	  try {
140	    const tb = require('./token-budget.cjs');
141	    const s = tb.getSessionStatus(projectDir);
142	    return (s && typeof s.pct === 'number') ? s.pct : (s && s.pct) || 'N/A';
143	  } catch (_) { return 'N/A'; }
144	}
145	
146	function _parseStartedAt(s) {
147	  if (!s) return Date.now();
148	  if (/^\d{4}-\d{2}-\d{2} \d{2}:\d{2}$/.test(s)) {
149	    const [d, t] = s.split(' ');
150	    return new Date(`${d}T${t}:00`).getTime();
151	  }
152	  const parsed = Date.parse(s);
153	  return Number.isFinite(parsed) ? parsed : Date.now();
154	}
155	
156	/**
157	 * Record a single spawn row to both token-log.md and token-usage.jsonl.
158	 *
159	 * @param {object} opts
160	 * @param {string} opts.projectDir
161	 * @param {string} opts.command        e.g. 'gsd-t-execute'
162	 * @param {string} opts.step           e.g. 'Step 4'
163	 * @param {string} opts.model          e.g. 'sonnet'
164	 * @param {string} opts.startedAt      'YYYY-MM-DD HH:MM'
165	 * @param {string} opts.endedAt        'YYYY-MM-DD HH:MM'
166	 * @param {object} [opts.usage]        Claude usage envelope; undefined → '—'
167	 * @param {string} [opts.domain]
168	 * @param {string} [opts.task]
169	 * @param {string|number} [opts.ctxPct]
170	 * @param {string} [opts.notes]
171	 * @param {'live'|'backfill'} [opts.source]
172	 * @param {string} [opts.sessionId]          v2 — stable session identifier
173	 * @param {string|number} [opts.turnId]      v2 — per-turn identifier within sessionId
174	 * @param {'in-session'|'headless'} [opts.sessionType]  v2 — channel classifier
175	 * @param {Array}  [opts.toolAttribution]    v2 — D2 joiner output; usually omitted by spawn callers
176	 * @param {object} [opts.compactionPressure] v2 — D5 runway snapshot; usually omitted by spawn callers
177	 * @returns {{tokenLogPath: string, jsonlPath: string}}
178	 */
179	function recordSpawnRow(opts) {
180	  const projectDir = opts.projectDir || '.';
181	  const tokenLogPath = opts.tokenLogPath || path.join(projectDir, '.gsd-t', 'token-log.md');
182	  const jsonlPath   = opts.jsonlPath   || path.join(projectDir, '.gsd-t', 'metrics', 'token-usage.jsonl');
183	
184	  const startMs = _parseStartedAt(opts.startedAt);
185	  const endMs   = _parseStartedAt(opts.endedAt);
186	  const durationSec = Math.max(0, Math.round((endMs - startMs) / 1000));
187	
188	  const tokensCell = _formatTokensCell(opts.usage);
189	  const notes = (opts.notes == null || opts.notes === '') ? '-' : String(opts.notes).replace(/\|/g, '\\|');
190	  const domain = (opts.domain == null || opts.domain === '') ? '-' : String(opts.domain);
191	  const task   = (opts.task   == null || opts.task   === '') ? '-' : String(opts.task);
192	  const ctxPct = (opts.ctxPct == null) ? 'N/A' : String(opts.ctxPct);
193	
194	  // skipMarkdownLog: JSONL is canonical (D3). The markdown log is a legacy view
195	  // kept in sync for human-readable tailing; high-frequency producers (D1
196	  // per-turn in-session rows, D2 joiner) should write JSONL-only and rely on
197	  // `gsd-t tokens --regenerate-log` for the markdown rendering.
198	  if (!opts.skipMarkdownLog) {
199	    _appendTokenLogRow(tokenLogPath, {
200	      startedAt: opts.startedAt,
201	      endedAt: opts.endedAt,
202	      command: opts.command,
203	      step: opts.step,
204	      model: opts.model,
205	      durationSec,
206	      tokensCell,
207	      notes,
208	      domain,
209	      task,
210	      ctxPct,
211	    });
212	  }
213	
214	  const milestone = opts.milestone || _inferMilestone(projectDir);
215	  _appendJsonlRecord(jsonlPath, _buildJsonlRecord({
216	    command: opts.command,
217	    step: opts.step,
218	    model: opts.model,
219	    startedAt: opts.startedAt,
220	    endedAt: opts.endedAt,
221	    durationSec,
222	    usage: opts.usage,
223	    domain: opts.domain || null,
224	    task: opts.task || null,
225	    notes: opts.notes || null,
226	    ctxPct: opts.ctxPct == null ? null : opts.ctxPct,
227	    milestone,
228	    source: opts.source || 'live',
229	    sessionId: opts.sessionId,
230	    turnId: opts.turnId,
231	    sessionType: opts.sessionType,
232	    toolAttribution: opts.toolAttribution,
233	    compactionPressure: opts.compactionPressure,
234	  }));
235	
236	  return { tokenLogPath, jsonlPath };
237	}
238	
239	/**
240	 * Wrap an async spawn callable; capture timing + usage + write the row.
241	 *
242	 * @param {object} opts
243	 * @param {string} opts.command
244	 * @param {string} opts.step
245	 * @param {string} opts.model
246	 * @param {string} opts.description
247	 * @param {string} [opts.projectDir='.']
248	 * @param {() => Promise<any>} opts.spawnFn
249	 * @param {string} [opts.domain]
250	 * @param {string} [opts.task]
251	 * @returns {Promise<{result: any, usage: any|undefined, rowWritten: {tokenLogPath, jsonlPath}}>}
252	 */
253	async function captureSpawn(opts) {
254	  if (!opts || typeof opts.spawnFn !== 'function') {
255	    throw new Error('captureSpawn: spawnFn is required and must be a function');
256	  }
257	  const projectDir = opts.projectDir || '.';
258	  const startDate = new Date();
259	  const startedAt = fmtDateTime(startDate);
260	  const startMs = startDate.getTime();
261	
262	  // Visible banner before the spawn fires
263	  process.stdout.write(`⚙ [${opts.model}] ${opts.command} → ${opts.description}\n`);
264	
265	  let result, caught;
266	  try {
267	    result = await opts.spawnFn();
268	  } catch (err) {
269	    caught = err;
270	  }
271	
272	  const endDate = new Date();
273	  const endedAt = fmtDateTime(endDate);
274	
275	  const usage = caught ? undefined : _parseUsageFromResult(result);
276	  const ctxPct = _resolveCtxPct(projectDir);
277	  const notes = caught ? `spawn_error: ${String(caught && caught.message || caught).slice(0, 200)}` : (opts.notes || '-');
278	
279	  const rowWritten = recordSpawnRow({
280	    projectDir,
281	    command: opts.command,
282	    step: opts.step,
283	    model: opts.model,
284	    startedAt,
285	    endedAt,
286	    usage,
287	    domain: opts.domain,
288	    task: opts.task,
289	    ctxPct,
290	    notes,
291	    sessionId: opts.sessionId,
292	    turnId: opts.turnId,
293	    sessionType: opts.sessionType,
294	    toolAttribution: opts.toolAttribution,
295	    compactionPressure: opts.compactionPressure,
296	  });
297	
298	  if (caught) throw caught;
299	  return { result, usage, rowWritten };
300	}
301	
302	module.exports = {
303	  captureSpawn,
304	  recordSpawnRow,
305	  _parseUsageFromResult,
306	  _formatTokensCell,
307	  _ensureTokenLogHeader,
308	  _buildJsonlRecord,
309	  SCHEMA_VERSION,
310	  NEW_HEADER,
311	  NEW_SEP,
312	};
313

