168	 * @param {string} [opts.task]
169	 * @param {string|number} [opts.ctxPct]
170	 * @param {string} [opts.notes]
171	 * @param {'live'|'backfill'} [opts.source]
172	 * @param {string} [opts.sessionId]          v2 — stable session identifier
173	 * @param {string|number} [opts.turnId]      v2 — per-turn identifier within sessionId
174	 * @param {'in-session'|'headless'} [opts.sessionType]  v2 — channel classifier
175	 * @param {Array}  [opts.toolAttribution]    v2 — D2 joiner output; usually omitted by spawn callers
176	 * @param {object} [opts.compactionPressure] v2 — D5 runway snapshot; usually omitted by spawn callers
177	 * @returns {{tokenLogPath: string, jsonlPath: string}}
