179	function recordSpawnRow(opts) {
180	  const projectDir = opts.projectDir || '.';
181	  const tokenLogPath = opts.tokenLogPath || path.join(projectDir, '.gsd-t', 'token-log.md');
182	  const jsonlPath   = opts.jsonlPath   || path.join(projectDir, '.gsd-t', 'metrics', 'token-usage.jsonl');
183	
184	  const startMs = _parseStartedAt(opts.startedAt);
185	  const endMs   = _parseStartedAt(opts.endedAt);
186	  const durationSec = Math.max(0, Math.round((endMs - startMs) / 1000));
187	
188	  const tokensCell = _formatTokensCell(opts.usage);
189	  const notes = (opts.notes == null || opts.notes === '') ? '-' : String(opts.notes).replace(/\|/g, '\\|');
190	  const domain = (opts.domain == null || opts.domain === '') ? '-' : String(opts.domain);
191	  const task   = (opts.task   == null || opts.task   === '') ? '-' : String(opts.task);
192	  const ctxPct = (opts.ctxPct == null) ? 'N/A' : String(opts.ctxPct);
193	
194	  // skipMarkdownLog: JSONL is canonical (D3). The markdown log is a legacy view
195	  // kept in sync for human-readable tailing; high-frequency producers (D1
196	  // per-turn in-session rows, D2 joiner) should write JSONL-only and rely on
197	  // `gsd-t tokens --regenerate-log` for the markdown rendering.
198	  if (!opts.skipMarkdownLog) {
199	    _appendTokenLogRow(tokenLogPath, {
200	      startedAt: opts.startedAt,
201	      endedAt: opts.endedAt,
202	      command: opts.command,
203	      step: opts.step,
204	      model: opts.model,
205	      durationSec,
206	      tokensCell,
207	      notes,
208	      domain,
209	      task,
210	      ctxPct,
211	    });
212	  }
213	
214	  const milestone = opts.milestone || _inferMilestone(projectDir);
215	  _appendJsonlRecord(jsonlPath, _buildJsonlRecord({
216	    command: opts.command,
217	    step: opts.step,
218	    model: opts.model,
219	    startedAt: opts.startedAt,
220	    endedAt: opts.endedAt,
221	    durationSec,
222	    usage: opts.usage,
223	    domain: opts.domain || null,
224	    task: opts.task || null,
225	    notes: opts.notes || null,
226	    ctxPct: opts.ctxPct == null ? null : opts.ctxPct,
227	    milestone,
228	    source: opts.source || 'live',
229	    sessionId: opts.sessionId,
230	    turnId: opts.turnId,
231	    sessionType: opts.sessionType,
232	    toolAttribution: opts.toolAttribution,
233	    compactionPressure: opts.compactionPressure,
234	  }));
