239	/**
240	 * Wrap an async spawn callable; capture timing + usage + write the row.
241	 *
242	 * @param {object} opts
243	 * @param {string} opts.command
244	 * @param {string} opts.step
245	 * @param {string} opts.model
246	 * @param {string} opts.description
247	 * @param {string} [opts.projectDir='.']
248	 * @param {() => Promise<any>} opts.spawnFn
249	 * @param {string} [opts.domain]
250	 * @param {string} [opts.task]
251	 * @returns {Promise<{result: any, usage: any|undefined, rowWritten: {tokenLogPath, jsonlPath}}>}
252	 */
253	async function captureSpawn(opts) {
254	  if (!opts || typeof opts.spawnFn !== 'function') {
255	    throw new Error('captureSpawn: spawnFn is required and must be a function');
256	  }
257	  const projectDir = opts.projectDir || '.';
258	  const startDate = new Date();
259	  const startedAt = fmtDateTime(startDate);
260	  const startMs = startDate.getTime();
261	
262	  // Visible banner before the spawn fires
263	  process.stdout.write(`⚙ [${opts.model}] ${opts.command} → ${opts.description}\n`);
264	
265	  let result, caught;
266	  try {
267	    result = await opts.spawnFn();
268	  } catch (err) {
269	    caught = err;
270	  }
271	
272	  const endDate = new Date();
273	  const endedAt = fmtDateTime(endDate);
274	
275	  const usage = caught ? undefined : _parseUsageFromResult(result);
276	  const ctxPct = _resolveCtxPct(projectDir);
277	  const notes = caught ? `spawn_error: ${String(caught && caught.message || caught).slice(0, 200)}` : (opts.notes || '-');
278	
279	  const rowWritten = recordSpawnRow({
280	    projectDir,
281	    command: opts.command,
282	    step: opts.step,
283	    model: opts.model,
284	    startedAt,
285	    endedAt,
286	    usage,
287	    domain: opts.domain,
288	    task: opts.task,
289	    ctxPct,
290	    notes,
291	    sessionId: opts.sessionId,
292	    turnId: opts.turnId,
293	    sessionType: opts.sessionType,
294	    toolAttribution: opts.toolAttribution,
295	    compactionPressure: opts.compactionPressure,
296	  });
297	
298	  if (caught) throw caught;
299	  return { result, usage, rowWritten };
300	}
